#include <bits/stdc++.h>
using namespace std;

int n, m, t[2005], q[2005];

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> t[i];
    }
    cin >> m;
    for (int i = 0; i < m; i++) {
        int x, cnt = 0;
        cin >> x;
        q[i] = t[x];
        for (int j = i; j > 0; j--) {
            if (j > 0) {
                if (q[j - 1] <= q[j]) break;
                if (j > 1) {
                    if (q[j - 2] != q[j - 1]) cnt++;
                }
                else cnt++;
                swap(q[j], q[j - 1]);
            }
        }
        // for (int j = 0; j < n; j++) cout << q[j] << ' ';
        // cout << endl;
        cout << cnt << endl;
    }
    return 0;
}
